head.script:
//==================================================================================================================
// id       : op_210_01_24b 
// 이름     : 상용직 소급분생성및수정
// 경로     : 물류/하역(인천)/실적/
// 작 성 자 : 조성빈
// 작 업 일 : 2026-04-03
// 사용계정 : 내부
// 비고     :  ***
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = async function() {
	scwin.lobranCd  = $c.gus.cfIsNull($c.data.getMemInfo("lobranCd")) ? "" : $c.data.getMemInfo("lobranCd");  // 물류 점소 코드

	//날짜 생성
	// Calendar today = Calendar.getInstance();
	// today.add(Calendar.YEAR,-1);
	// SimpleDateFormat sdf = new SimpleDateFormat("yyyy");
	// String vLastYYYY = sdf.format(today.getTime());

	// today.add(Calendar.YEAR,-1);
	// SimpleDateFormat sdf2 = new SimpleDateFormat("yyyy");
	// String vBefLastYYYY = sdf2.format(today.getTime());

	scwin.vLastYYYY     = $c.date.addMonth($c.date.getServerDateTime("yyyyMMdd"), -12).substr(0,4);
	scwin.vBefLastYYYY  = $c.date.addMonth($c.date.getServerDateTime("yyyyMMdd"), -24).substr(0,4);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(async function() {

        co_ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
        co_ds_combo1_search.set("queryId", "retriveLobranCodeList");
        var rs = await $c.sbm.execute(sbm_lobranCd);
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            co_ds_combo1.setJSON(rs.responseJSON.GAUCE);
            co_ds_combo1.sort("code", 0);

            scwin.f_SetDefaultData();

            $c.gus.cfDisableObjects([btn_Save, btn_Create, btn_Cancel]);
            cbx_includeRetireYn.setSelectedIndex(1);

            // $p.setTimeout(function() {
            //     // ica_reYm.setValue("202504");
            //     // lc_lobranCd.setValue("4AA");
            //     ica_reYm.setValue("202205");
            //     lc_lobranCd.setValue("4AA");
            // }, {"delay":1200});

        };

    }, {"delay":50});
};

scwin.f_SetDefaultData = function () {
    ica_reYm.setValue(scwin.vLastYYYY + "04");
    lc_lobranCd.setValue(scwin.lobranCd);
    lc_lobranCd.focus();

    ica_newWageAgrmntDt.setValue(scwin.vLastYYYY + "0401");
    ica_oldWageAgrmntDt.setValue(scwin.vBefLastYYYY + "0401");
    lc_wrkPlClsCd.setValue("02");

    txt_reYm.setValue(scwin.vLastYYYY + "04");
    txt_lobranNm.setValue(lc_lobranCd.getText(true));
    txt_wrkPlClsNm.setValue(lc_wrkPlClsCd.getValue() + " : " + lc_wrkPlClsCd.getText(true));
};

// 소급분 세부내역 조회
scwin.f_Retrieve = async function () {
    // 검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([lc_lobranCd, ica_reYm, lc_wrkPlClsCd])) {
        return;
    }

    if (cbx_includeRetireYn.getValue() == "true") {
        ds_condition.set("includeRetireYn", "Y");
    } else {
        ds_condition.set("includeRetireYn", "N");
    }
    ds_condition.set("spRtn",0);
    $c.sbm.execute(sbm_retrieve);
};

// 기본임금 수정
scwin.f_Save = async function () {
    var modifyRowCnt = ds_master.getModifiedIndex().length
    if (modifyRowCnt > 0) {
        if (!await $c.gus.cfValidate([gr_master], null, true)) return;	
        if (await $c.win.confirm(MSG_CM_CRM_001)){
            $c.sbm.execute(sbm_save);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["상용직 소급분세부내역"]); // @은(는) 변경된 사항이 없습니다
    }		
};

scwin.f_Create = async function (cls) {
    var clsstr = "";

    // 필수 입력 체크
    if (!await $c.gus.cfValidate([lc_lobranCd, ica_reYm, lc_wrkPlClsCd])) {
        return;
    }

    if (ica_newWageAgrmntDt.getValue().trim().length != 8 ) {
        await $c.win.alert("(인상후)협약일자는 필수입력입니다.");
        ica_newWageAgrmntDt.focus();
        return;
    }
    if (ica_oldWageAgrmntDt.getValue().trim().length != 8 ) {
        await $c.win.alert("(인상전)협약일자는 필수입력입니다.");
        ica_oldWageAgrmntDt.focus();
        return;
    }

    var reYm = ica_reYm.getValue();
    reYm = reYm.substr(0,4) + "년 " + reYm.substr(5,6) + "월 ";

    if (cls == 1) {
        if (ds_master.getRowCount() == 0) {
            clsstr = "소급분 내역을 생성";
        } else {
            clsstr = "생성된 소급분 내역이 있습니다. 재생성 ";
        }
    }  else if (cls ==  2 ) {
        clsstr = "소급분내역을 삭제";
    }

    if (!await $c.win.confirm( reYm + clsstr + " 하시겠습니까?") ) {
        return;
    }

    if (cls == 1) {
        $c.sbm.execute(sbm_create);
    }  else if (cls ==  2 ) {
        $c.sbm.execute(sbm_cancel);
    }
};

scwin.f_gridToExcel = function (argGrid, argTitle) {
    // argGrid.SetExcelTitle(1,"value:" + argTitle + ";" // 표시할 타이틀
    //                     + "font-face:'돋움체';"      // 폰트
    //                     + "font-size:16pt;"         // 폰트 크기
    //                     + "font-color:black;"       // 폰트 색깔
    //                     + "bgcolor:#ffffff;"        // 배경 색깔
    //                     + "align:center;"           // 정렬
    //                     + "line-color:white;"       // 타이틀 부분 테두리선 색깔
    //                     + "line-width:0pt;"         // 타이틀 테두리선 굵기
    //                     + "skiprow:1;");            // 타이틀 다음 떼는 로우 수
    var vFileName   = "소급분(세부내역)_" + ica_reYm.getValue();
    // cfGridToExcel(argGrid, argTitle, vFileName+"", 4+8+16);

    var argGridTotalCol = 0;
    for (var i = 0 ; i < argGrid.getTotalCol(); i++) {
        if (argGrid.getColumnVisible(i)) {
            argGridTotalCol++;
        }
    }

    const infoArr = [{
          rowIndex    : 0
        , colIndex    : 0
        , rowSpan     : 1
        , colSpan     : argGridTotalCol
        , text        : argTitle
        , textAlign   : "center"
        , fontSize    : "16"
        , fontName    : "돋움체"
        , color       : "black"
        , fontWeight  : ""
        , drawBorder  : "false"
        , borderColor : ""
        , borderWidth : ""
        , wordWrap    : "true"
        , bgColor     : "#ffffff"
    }];
    const options = {
        fileName : vFileName + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: argTitle,
        type : "1",
        startRowIndex: 2,
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(argGrid, options, infoArr);

};

// 검색영역 Field Clear함.
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_InitObjects();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.excelDown = function (e) {
    scwin.f_gridToExcel(gr_master, '소급분(세부내역)');
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_Create_onclick = function (e) {
    scwin.f_Create(1);
};

scwin.btn_Cancel_onclick = function (e) {
    scwin.f_Create(2);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {

    } else {
        // 총 조회건수 표시
        var rowCnt = ds_master.getRowCount();
        txt_totalRows.setValue(rowCnt);

        if (rowCnt == 0) {			
            await $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
            $c.gus.cfDisableObjects([btn_Save, btn_Cancel]);
            $c.gus.cfEnableObjects([btn_Create]);
        } else {
            $c.gus.cfEnableObjects([btn_Save, btn_Create, btn_Cancel]);
        } 		
    } 
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {

    } else {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001); // "성공적으로 저장하였습니다."
	    scwin.f_Retrieve();
    } 
};

scwin.sbm_create_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {

    } else {
        scwin.f_Retrieve();
    } 
};

scwin.ica_reYm_onblur = function (e) {
    if (ica_reYm.getValue() != "" && ica_reYm.getValue().trim()!= "") {
		txt_reYm.setValue(ica_reYm.getValue().substring(0, 4) + "/" + ica_reYm.getValue().substring(4, 6));
	}
};

scwin.lc_lobranCd_onselected = function () {
};

scwin.lc_wrkPlClsCd_onselected = function () {
    txt_wrkPlClsNm.setValue(lc_wrkPlClsCd.getValue() + ":" + lc_wrkPlClsCd.getText(true));
};

scwin.lc_lobranCd_onchange = function (info) {
    txt_lobranNm.setValue(lc_lobranCd.getText(true));

};

scwin.f_decodeVal = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = floatVal.toFixed(0);
        return $c.gus.cfInsertComma(formattedVal);
    }
}

scwin.f_decodeVal_1 = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = floatVal.toFixed(1);
        return $c.gus.cfInsertComma(formattedVal);
    }
}

scwin.f_decodeVal_2 = function (data, formattedData, rowIndex, colIndex) {
    if (data == 0)
        return "";
    else {
        var floatVal = parseFloat(data);
        var formattedVal = floatVal.toFixed(2);
        return $c.gus.cfInsertComma(formattedVal);
    }
}
